INSERT INTO incident_citations (incident_id, citation_key, tool_name, command, output, executed_at, created_at) VALUES (E'859b8ade-7269-4c18-9389-de25468b5905', E'1', E'unknown', E'aws rds describe-db-instances --db-instance-identifier generated-mysql-db --region us-east-1 --query ''DBInstances[0].[DBInstanceIdentifier,DBInstanceStatus,PendingModifiedValues,DBParameterGroups]'' --output json', E'[\n  "generated-mysql-db",\n  "available",\n  {},\n  [\n    {\n      "DBParameterGroupName": "default.mysql8.0",\n      "ParameterApplyStatus": "in-sync"\n    }\n  ]\n]', E'2026-03-27T13:13:25.320423', E'2026-03-27T13:13:40.433462');
INSERT INTO incident_citations (incident_id, citation_key, tool_name, command, output, executed_at, created_at) VALUES (E'859b8ade-7269-4c18-9389-de25468b5905', E'2', E'MCP: Get File Contents', E'src/services/order-processor.js', E'successfully downloaded text file (SHA: 48b84ba9639c26b495929e7c3a2baad58e804cb8)', E'2026-03-27T13:13:25.320487', E'2026-03-27T13:13:40.433462');
INSERT INTO incident_citations (incident_id, citation_key, tool_name, command, output, executed_at, created_at) VALUES (E'859b8ade-7269-4c18-9389-de25468b5905', E'3', E'Terminal', E'curl -s https://raw.githubusercontent.com/beng360/checkout-service/main/src/services/order-processor.js', E'const { query, getClient } = require(''../db/pool'');\nconst { logger } = require(''../utils/logger'');\n\n/**\n * Process a checkout order using a transaction:\n * 1. Validate inventory\n * 2. Create order record\n * 3. Reserve inventory\n * 4. Initiate payment\n *\n * Refactored to use explicit transactions for atomicity.\n */\nasync function processOrder(userId, cartItems, paymentMethod) {\n  const orderId = `ord-${Date.now().toString(36)}`;\n  const client = await getClient();\n\n  logger.info(`Processing order ${orderId} for user ${userId}`, {\n    orderId,\n    userId,\n    itemCount: cartItems.length,\n  });\n\n  try {\n    await client.query(''BEGIN'');\n\n    // Step 1: Check inventory for all items\n    for (const item of cartItems) {\n      const result = await client.query(\n        ''SELECT sku, quantity_available FROM inventory WHERE sku = $1 FOR UPDATE'',\n        [item.sku]\n      );\n\n      if (!result.rows[0] || result.rows[0].quantity_available < item.quantity) {\n        throw new Error(`Insufficient inventory for SKU ${item.sku}`);\n      }\n    }\n\n    // Step 2: Create order record\n    const total = cartItems.reduce((sum, item) => sum + item.price * item.quantity, 0);\n    await client.query(\n      ''INSERT INTO orders (id, user_id, total, status, created_at) VALUES ($1, $2, $3, $4, NOW())'',\n      [orderId, userId, total, ''pending'']\n    );\n\n    // Step 3: Reserve inventory\n    for (const item of cartItems) {\n      await client.query(\n        ''UPDATE inventory SET quantity_available = quantity_available - $1 WHERE sku = $2'',\n        [item.quantity, item.sku]\n      );\n\n      await client.query(\n        ''INSERT INTO order_items (order_id, sku, quantity, price) VALUES ($1, $2, $3, $4)'',\n        [orderId, item.sku, item.quantity, item.price]\n      );\n    }\n\n    // Step 4: Process payment\n    await client.query(\n      ''UPDATE orders SET status = $1, payment_method = $2 WHERE id = $3'',\n      [''processing'', paymentMethod, orderId]\n    );\n\n    await client.query(''COMMIT'');\n\n    logger.info(`Order ${orderId} created successfully`, { orderId, total });\n\n    return { orderId, total, status: ''processing'' };\n  } catch (error) {\n    await client.query(''ROLLBACK'');\n    throw error;\n  }\n  // BUG: client.release() is never called!\n  // The finally block from the old implementation was removed during\n  // the refactor to transactions, but the connection release was not\n  // added after the try/catch. Each failed AND successful request\n  // leaks a connection back to the pool.\n}\n\nmodule.exports = { processOrder };\n', E'2026-03-27T13:13:25.320526', E'2026-03-27T13:13:40.433462');
INSERT INTO incident_citations (incident_id, citation_key, tool_name, command, output, executed_at, created_at) VALUES (E'859b8ade-7269-4c18-9389-de25468b5905', E'5', E'jira_search_issues', E'Command not available', E'{\n  "status": "success",\n  "total": 7,\n  "count": 7,\n  "issues": [\n    {\n      "key": "RCA-45",\n      "summary": "Connection pool leak in order-processor.js \\u2014 client.release() missing after transaction refactor",\n      "status": "To Do",\n      "assignee": "Benjamin Gervais",\n      "priority": "Highest",\n      "created": "2026-03-26T17:54:53.284-0400",\n      "updated": "2026-03-27T08:59:32.847-0400",\n      "labels": []\n    },\n    {\n      "key": "RCA-39",\n      "summary": "Incident: Kubernetes Pod Crash Loop - checkout-service (OOMKilled)",\n      "status": "To Do",\n      "assignee": "Benjamin Gervais",\n      "priority": "Medium",\n      "created": "2026-03-21T12:43:06.876-0400",\n      "updated": "2026-03-26T17:49:53.918-0400",\n      "labels": [\n        "checkout-service",\n        "critical",\n        "kubernetes",\n        "memory-leak",\n        "oomkilled",\n        "production"\n      ]\n    },\n    {\n      "key": "RCA-42",\n      "summary": "Incident: production-web-01 \\u2014 High CPU Usage from Cascading Memory Leak Failures",\n      "status": "To Do",\n      "assignee": "Benjamin Gervais",\n      "priority": "Medium",\n      "created": "2026-03-26T09:52:41.177-0400",\n      "updated": "2026-03-26T16:52:58.414-0400",\n      "labels": []\n    },\n    {\n      "key": "RCA-20",\n      "summary": "[PIPELINE FAILURE] Health Check \\u2014 /health Returns HTTP 500 (Stage 4)",\n      "status": "To Do",\n      "assignee": "Benjamin Gervais",\n      "priority": "Highest",\n      "created": "2026-03-04T15:55:00.444-0500",\n      "updated": "2026-03-25T14:43:09.091-0400",\n      "labels": [\n        "database",\n        "health-check",\n        "pipeline-failure",\n        "rca"\n      ]\n    },\n    {\n      "key": "RCA-7",\n      "summary": "[BUG] Memory Leak \\u2014 /api/data Appends 1MB per Request (Extended Checks)",\n      "status": "To Do",\n      "assignee": "Benjamin Gervais",\n      "priority": "High",\n      "created": "2026-03-04T15:53:29.476-0500",\n      "updated": "2026-03-25T12:28:31.247-0400",\n      "labels": [\n        "memory-leak",\n        "performance",\n        "rca"\n      ]\n    },\n    {\n      "key": "RCA-40",\n      "summary": "Incident: DNS Resolution Failures - ingress-controller (CoreDNS)",\n      "status": "To Do",\n      "assignee": "Benjamin Gervais",\n      "priority": "Medium",\n      "created": "2026-03-21T14:48:32.160-0400",\n      "updated": "2026-03-21T14:48:32.417-0400",\n      "labels": [\n        "coredns",\n        "critical",\n        "dns",\n        "ingress-controller",\n        "network",\n        "production"\n      ]\n    },\n    {\n      "key": "RCA-37",\n      "summary": "Incident: Spanner latency issues",\n      "status": "To Do",\n      "assignee": "Benjamin Gervais",\n      "priority": "Medium",\n      "created": "2026-03-05T12:15:51.148-0500",\n      "updated": "2026-03-21T11:43:12.508-0400",\n      "labels": []\n    }\n  ]\n}', E'2026-03-27T13:13:25.32074', E'2026-03-27T13:13:40.433462');
INSERT INTO incident_citations (incident_id, citation_key, tool_name, command, output, executed_at, created_at) VALUES (E'859b8ade-7269-4c18-9389-de25468b5905', E'6', E'jira_add_comment', E'Command not available', E'{\n  "status": "success",\n  "commentId": "10188",\n  "issueKey": "RCA-45",\n  "url": "https://arvoai.atlassian.net/browse/RCA-45?focusedId=10188&page=com.atlassian.jira.plugin.system.issuetabpanels:comment-tabpanel#comment-10188"\n}', E'2026-03-27T13:13:25.320827', E'2026-03-27T13:13:40.433462');

