INSERT INTO incident_suggestions (incident_id, title, description, type, risk, command, file_path, original_content, suggested_content, user_edited_content, repository, pr_url, pr_number, created_branch, applied_at, created_at) VALUES (E'859b8ade-7269-4c18-9389-de25468b5905', E'Fix order-processor.js: Add missing client.release() in finally block to p...', E'Add missing client.release() in finally block to prevent connection pool leak\n\n**Root Cause:** During the refactor to explicit transactions in v2.4.1 (commit 526d28c5), the finally block that released database connections was removed. Every checkout request now leaks a connection, exhausting the 50-connection pool within minutes and causing cascading failures across all production hosts.', E'fix', E'medium', E'fix: add missing client.release() in processOrder finally block\n\nFixes connection pool leak introduced in v2.4.1 transaction refactor.\nEvery checkout request was leaking a database connection because the\nfinally block that released connections was removed during the refactor.\n\nThis caused the pool to exhaust (50/50 connections) within minutes,\nleading to 72% error rate, OOMKill risk (948MB/1024MB), and cascading\nfailures across cart-service and payment-gateway.\n\nFixes RCA-44, RCA-45', E'src/services/order-processor.js', E'const { query, getClient } = require(''../db/pool'');\nconst { logger } = require(''../utils/logger'');\n\n/**\n * Process a checkout order using a transaction:\n * 1. Validate inventory\n * 2. Create order record\n * 3. Reserve inventory\n * 4. Initiate payment\n *\n * Refactored to use explicit transactions for atomicity.\n */\nasync function processOrder(userId, cartItems, paymentMethod) {\n  const orderId = `ord-${Date.now().toString(36)}`;\n  const client = await getClient();\n\n  logger.info(`Processing order ${orderId} for user ${userId}`, {\n    orderId,\n    userId,\n    itemCount: cartItems.length,\n  });\n\n  try {\n    await client.query(''BEGIN'');\n\n    // Step 1: Check inventory for all items\n    for (const item of cartItems) {\n      const result = await client.query(\n        ''SELECT sku, quantity_available FROM inventory WHERE sku = $1 FOR UPDATE'',\n        [item.sku]\n      );\n\n      if (!result.rows[0] || result.rows[0].quantity_available < item.quantity) {\n        throw new Error(`Insufficient inventory for SKU ${item.sku}`);\n      }\n    }\n\n    // Step 2: Create order record\n    const total = cartItems.reduce((sum, item) => sum + item.price * item.quantity, 0);\n    await client.query(\n      ''INSERT INTO orders (id, user_id, total, status, created_at) VALUES ($1, $2, $3, $4, NOW())'',\n      [orderId, userId, total, ''pending'']\n    );\n\n    // Step 3: Reserve inventory\n    for (const item of cartItems) {\n      await client.query(\n        ''UPDATE inventory SET quantity_available = quantity_available - $1 WHERE sku = $2'',\n        [item.quantity, item.sku]\n      );\n\n      await client.query(\n        ''INSERT INTO order_items (order_id, sku, quantity, price) VALUES ($1, $2, $3, $4)'',\n        [orderId, item.sku, item.quantity, item.price]\n      );\n    }\n\n    // Step 4: Process payment\n    await client.query(\n      ''UPDATE orders SET status = $1, payment_method = $2 WHERE id = $3'',\n      [''processing'', paymentMethod, orderId]\n    );\n\n    await client.query(''COMMIT'');\n\n    logger.info(`Order ${orderId} created successfully`, { orderId, total });\n\n    return { orderId, total, status: ''processing'' };\n  } catch (error) {\n    await client.query(''ROLLBACK'');\n    throw error;\n  }\n  // BUG: client.release() is never called!\n  // The finally block from the old implementation was removed during\n  // the refactor to transactions, but the connection release was not\n  // added after the try/catch. Each failed AND successful request\n  // leaks a connection back to the pool.\n}\n\nmodule.exports = { processOrder };\n', E'const { query, getClient } = require(''../db/pool'');\nconst { logger } = require(''../utils/logger'');\n\n/**\n * Process a checkout order using a transaction:\n * 1. Validate inventory\n * 2. Create order record\n * 3. Reserve inventory\n * 4. Initiate payment\n *\n * Refactored to use explicit transactions for atomicity.\n */\nasync function processOrder(userId, cartItems, paymentMethod) {\n  const orderId = `ord-${Date.now().toString(36)}`;\n  const client = await getClient();\n\n  logger.info(`Processing order ${orderId} for user ${userId}`, {\n    orderId,\n    userId,\n    itemCount: cartItems.length,\n  });\n\n  try {\n    await client.query(''BEGIN'');\n\n    // Step 1: Check inventory for all items\n    for (const item of cartItems) {\n      const result = await client.query(\n        ''SELECT sku, quantity_available FROM inventory WHERE sku = $1 FOR UPDATE'',\n        [item.sku]\n      );\n\n      if (!result.rows[0] || result.rows[0].quantity_available < item.quantity) {\n        throw new Error(`Insufficient inventory for SKU ${item.sku}`);\n      }\n    }\n\n    // Step 2: Create order record\n    const total = cartItems.reduce((sum, item) => sum + item.price * item.quantity, 0);\n    await client.query(\n      ''INSERT INTO orders (id, user_id, total, status, created_at) VALUES ($1, $2, $3, $4, NOW())'',\n      [orderId, userId, total, ''pending'']\n    );\n\n    // Step 3: Reserve inventory\n    for (const item of cartItems) {\n      await client.query(\n        ''UPDATE inventory SET quantity_available = quantity_available - $1 WHERE sku = $2'',\n        [item.quantity, item.sku]\n      );\n\n      await client.query(\n        ''INSERT INTO order_items (order_id, sku, quantity, price) VALUES ($1, $2, $3, $4)'',\n        [orderId, item.sku, item.quantity, item.price]\n      );\n    }\n\n    // Step 4: Process payment\n    await client.query(\n      ''UPDATE orders SET status = $1, payment_method = $2 WHERE id = $3'',\n      [''processing'', paymentMethod, orderId]\n    );\n\n    await client.query(''COMMIT'');\n\n    logger.info(`Order ${orderId} created successfully`, { orderId, total });\n\n    return { orderId, total, status: ''processing'' };\n  } catch (error) {\n    await client.query(''ROLLBACK'');\n    throw error;\n  } finally {\n    // CRITICAL FIX: Release the database connection back to the pool\n    // This ensures connections are returned whether the transaction succeeds or fails\n    client.release();\n  }\n}\n\nmodule.exports = { processOrder };\n', NULL, E'beng360/checkout-service', NULL, NULL, NULL, NULL, E'2026-03-27T13:12:22.83742');
INSERT INTO incident_suggestions (incident_id, title, description, type, risk, command, file_path, original_content, suggested_content, user_edited_content, repository, pr_url, pr_number, created_branch, applied_at, created_at) VALUES (E'859b8ade-7269-4c18-9389-de25468b5905', E'Check active RDS connections for leak quantification', E'Query the MySQL information_schema to count active and sleeping connections on the generated-mysql-db instance, quantifying how many leaked connections are currently held before restarting the service.', E'diagnostic', E'safe', E'aws rds describe-db-instances --db-instance-identifier generated-mysql-db --region us-east-1 --query ''DBInstances[0].[DBInstanceIdentifier,DBInstanceStatus,Endpoint,MultiAZ,DBInstanceClass]'' --output json', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, E'2026-03-27T13:13:50.216765');
INSERT INTO incident_suggestions (incident_id, title, description, type, risk, command, file_path, original_content, suggested_content, user_edited_content, repository, pr_url, pr_number, created_branch, applied_at, created_at) VALUES (E'859b8ade-7269-4c18-9389-de25468b5905', E'Inspect checkout-service pod memory and connection logs', E'Stream recent logs from the checkout-service pod to confirm connection pool exhaustion errors and observe memory pressure patterns leading up to the OOM-risk alert.', E'diagnostic', E'safe', E'kubectl logs -n production -l app=checkout-service --tail=200 --since=1h | grep -E ''pool|connection|OOM|memory|getClient|release|error'' ', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, E'2026-03-27T13:13:50.216765');
INSERT INTO incident_suggestions (incident_id, title, description, type, risk, command, file_path, original_content, suggested_content, user_edited_content, repository, pr_url, pr_number, created_branch, applied_at, created_at) VALUES (E'859b8ade-7269-4c18-9389-de25468b5905', E'Restart checkout-service deployment to clear leaked connections', E'Rolling restart of the checkout-service deployment will terminate pods holding leaked database connections, immediately relieving memory pressure while the RCA-45 code fix is prepared for deployment.', E'mitigation', E'medium', E'kubectl rollout restart deployment/checkout-service -n production && kubectl rollout status deployment/checkout-service -n production --timeout=120s', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, E'2026-03-27T13:13:50.216765');
INSERT INTO incident_suggestions (incident_id, title, description, type, risk, command, file_path, original_content, suggested_content, user_edited_content, repository, pr_url, pr_number, created_branch, applied_at, created_at) VALUES (E'859b8ade-7269-4c18-9389-de25468b5905', E'Audit other transaction handlers for missing client.release() calls', E'Search the repository source tree for all usages of getClient() that lack a corresponding client.release(), identifying any other files affected by the same refactor pattern documented in RCA-45.', E'diagnostic', E'safe', E'curl -s https://raw.githubusercontent.com/beng360/checkout-service/main/src/services/order-processor.js | grep -n ''getClient\\|client.release\\|client.query\\|BEGIN\\|COMMIT\\|ROLLBACK''', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, E'2026-03-27T13:13:50.216765');

-- Fixup: reassign demo data to the first admin user/org in the DB
-- so the demo works regardless of which users exist
DO $$
DECLARE
  v_user_id TEXT;
  v_org_id TEXT;
BEGIN
  SELECT u.id, u.org_id INTO v_user_id, v_org_id
    FROM users u WHERE u.org_id IS NOT NULL ORDER BY u.created_at LIMIT 1;

  IF v_user_id IS NULL THEN
    RAISE NOTICE 'No users with org_id found, skipping fixup';
    RETURN;
  END IF;

  UPDATE incidents       SET user_id = v_user_id, org_id = v_org_id WHERE id = '859b8ade-7269-4c18-9389-de25468b5905';
  UPDATE chat_sessions   SET user_id = v_user_id, org_id = v_org_id WHERE id = 'a7afc8b2-16f9-43cc-81dc-dfe41f610c3b';
  UPDATE incident_alerts SET user_id = v_user_id, org_id = v_org_id WHERE incident_id = '859b8ade-7269-4c18-9389-de25468b5905';
  UPDATE newrelic_events SET user_id = v_user_id, org_id = v_org_id WHERE id = 37;
END $$;
